def clean_name(url):
    fn = url.split('/')[-1].split('?')[0]
    fn = urllib.request.unquote(fn).replace('+', '_')
    fn = re.sub(r'[^a-zA-Z0-9._-]', '_', fn).strip('_')
    return fn or 'img.jpg'

total = sum(len(v) for v in URLS.values())
done = 0

for cat, urls in URLS.items():
    folder = os.path.join(DEST, cat)
    os.makedirs(folder, exist_ok=True)
    print(f'\n[{cat.upper()}] {len(urls)} imagens → {folder}')
    for url in urls:
        filename = clean_name(url)
        dest = os.path.join(folder, filename)
        if os.path.exists(dest):
            done += 1
            continue
        try:
            req = urllib.request.Request(url, headers=HEADERS)
            with urllib.request.urlopen(req, timeout=30) as r, open(dest, 'wb') as f:
                f.write(r.read())
            done += 1
            print(f'  [{done}/{total}] {filename}')
        except Exception as e:
            print(f'  ERRO {filename}: {e}')
        time.sleep(0.2)

print(f'\nConcluído: {done}/{total} imagens baixadas.')
print(f'Pasta: {DEST}')
